import React, { useEffect, useState, useRef, useContext } from 'react';
import { io } from 'socket.io-client';
import axios from 'axios';
import { useParams, useLocation, useNavigate } from 'react-router-dom';
import AuthContext from '../context/AuthContext';
import './Chat.css';

const socket = io('http://localhost:5001');

function Chat() {
  const { receiverId } = useParams();
  const location = useLocation();
  const navigate = useNavigate();
  const { user } = useContext(AuthContext);
  const [message, setMessage] = useState('');
  const [messages, setMessages] = useState([]);
  const [wordCount, setWordCount] = useState(0);
  const messagesEndRef = useRef(null);
  const caName = location.state?.caName || "Expert";

  const WORD_LIMIT = 350;

  useEffect(() => {
    if (!user) {
      navigate('/login');
      return;
    }

    // Fetch message history
    axios.get(`http://localhost:5001/api/chat/${user.id || user._id}/${receiverId}`)
      .then(res => {
        setMessages(res.data);
        // Calculate total words sent by user in this chat
        const count = res.data
          .filter(m => m.sender === (user.id || user._id))
          .reduce((acc, m) => acc + m.content.trim().split(/\s+/).length, 0);
        setWordCount(count);
      });

    socket.on('receiveMessage', msg => {
      const currentUserId = (user?.id || user?._id)?.toString();
      const targetId = receiverId?.toString();

      if (!currentUserId || !targetId) return;

      const msgSender = msg.sender?.toString();
      const msgReceiver = msg.receiver?.toString();

      if (
        (msgSender === currentUserId && msgReceiver === targetId) ||
        (msgSender === targetId && msgReceiver === currentUserId)
      ) {
        setMessages(prev => {
          // Prevent duplicates if optimistic update already added it
          const exists = prev.some(m => m._id === msg._id || (m.tempId && m.content === msg.content && m.sender === msg.sender));
          if (exists) return prev;
          return [...prev, msg];
        });

        if (msgSender === currentUserId) {
           setWordCount(prev => prev + msg.content.trim().split(/\s+/).length);
        }
      }
    });

    return () => socket.off('receiveMessage');
  }, [receiverId, user, navigate, wordCount]);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  const sendMessage = (e) => {
    e.preventDefault();
    if (!message.trim() || !user) return;

    const newWords = message.trim().split(/\s+/).length;

    // Check limit for non-subscribed users
    if (!user.isSubscribed && (wordCount + newWords) > WORD_LIMIT) {
      alert(`You have reached the free limit of ${WORD_LIMIT} words. Please subscribe to continue chatting!`);
      navigate('/subscription');
      return;
    }

    const messageData = {
      sender: (user.id || user._id).toString(),
      receiver: receiverId.toString(),
      content: message,
      timestamp: new Date().toISOString(),
      tempId: Date.now() // For optimistic UI
    };

    // Optimistic update
    setMessages(prev => [...prev, messageData]);

    socket.emit('sendMessage', messageData);
    setMessage('');
  };

  if (!user) return <div className="loading-state">Redirecting to login...</div>;

  return (
    <div className="chat-page container">
      <div className="chat-container card">
        <div className="chat-header">
          <div className="chat-user-info">
            <div className="avatar-small">{caName.charAt(0)}</div>
            <div>
              <h3>{caName}</h3>
              <span className="status-online">Online</span>
            </div>
          </div>
          {user && !user.isSubscribed && (
            <div className="word-limit-info">
              <div className="limit-bar">
                <div className="limit-progress" style={{ width: `${Math.min(100, (wordCount / WORD_LIMIT) * 100)}%` }}></div>
              </div>
              <span>{wordCount} / {WORD_LIMIT} free words</span>
            </div>
          )}
        </div>

        <div className="chat-messages">
          {messages.map((m, i) => {
            const currentUserId = (user.id || user._id)?.toString();
            const isSent = m.sender.toString() === currentUserId;
            return (
              <div key={i} className={`chat-message ${isSent ? 'sent' : 'received'}`}>
                <div className="message-bubble">
                  {m.content}
                </div>
              </div>
            );
          })}
          <div ref={messagesEndRef} />
        </div>

        <form className="chat-input-area" onSubmit={sendMessage}>
          <input 
            value={message} 
            onChange={e => setMessage(e.target.value)} 
            placeholder="Type your message..."
          />
          <button type="submit" className="btn btn-primary">Send</button>
        </form>
      </div>
    </div>
  );
}

export default Chat;
